const message = $input.first().json;

const sender = message.from?.emailAddress?.address || 'unknown';
const subject = message.subject || '';
const body = message.bodyPreview || message.body || '';

// Classification logic
let category = 'COLD';
let score = 0;

const hotKeywords = ['buy', 'purchase', 'quote', 'demo', 'interested', 'want to buy', 'pricing'];
const warmKeywords = ['information', 'learn more', 'details', 'interested', 'tell me'];
const coldKeywords = ['unsubscribe', 'spam', 'newsletter'];
const spamKeywords = ['viagra', 'casino', 'lottery', 'click here', 'urgent action'];

const text = (subject + ' ' + body).toLowerCase();

if (spamKeywords.some(kw => text.includes(kw))) {
  category = 'SPAM';
  score = 0;
} else if (hotKeywords.some(kw => text.includes(kw))) {
  category = 'HOT';
  score = 90;
} else if (warmKeywords.some(kw => text.includes(kw))) {
  category = 'WARM';
  score = 60;
} else {
  category = 'COLD';
  score = 30;
}

let action = '';
switch(category) {
  case 'HOT':
    action = 'Immediate follow-up required';
    break;
  case 'WARM':
    action = 'Schedule follow-up';
    break;
  case 'COLD':
    action = 'Add to nurture list';
    break;
  case 'SPAM':
    action = 'Mark as spam';
    break;
}

return {
  sender,
  subject,
  category,
  score,
  summary: `${sender} - ${category} lead`,
  action,
  timestamp: new Date().toISOString(),
  originalMessage: {
    from: message.from,
    subject: message.subject,
    body: body.substring(0, 200)
  }
};
